509:      * @return the number of split batches.
510:      */
511:     public int splitAndReenqueue(ProducerBatch bigBatch) {
512:         // Reset the estimated compression ratio to the initial value or the big batch compression ratio, whichever
513:         // is bigger. There are several different ways to do the reset. We chose the most conservative one to ensure
514:         // the split doesn't happen too often.
515:         CompressionRatioEstimator.setEstimation(bigBatch.topicPartition.topic(), compression.type(),
516:                                                 Math.max(1.0f, (float) bigBatch.compressionRatio()));
517:         Deque<ProducerBatch> dq = bigBatch.split(this.batchSize);
518:         int numSplitBatches = dq.size();
519:         Deque<ProducerBatch> partitionDequeue = getOrCreateDeque(bigBatch.topicPartition);
520:         while (!dq.isEmpty()) {
521:             ProducerBatch batch = dq.pollLast();
522:             incomplete.add(batch);
523:             // We treat the newly split batches as if they are not even tried.
524:             synchronized (partitionDequeue) {
525:                 if (transactionManager != null) {
526:                     // We should track the newly created batches since they already have assigned sequences.
527:                     transactionManager.addInFlightBatch(batch);
528:                     insertInSequenceOrder(partitionDequeue, batch);
529:                 } else {
