966:     public void updateNodeLatencyStats(Integer nodeId, long nowMs, boolean canDrain) {
967:         // Don't bother with updating stats if the feature is turned off.
968:         if (partitionAvailabilityTimeoutMs <= 0)
969:             return;
970: 
971:         // When the sender gets a node (returned by the ready() function) that has data to send
972:         // but the node is not ready (and so we cannot drain the data), we only update the
973:         // ready time, then the difference would reflect for how long a node wasn't ready
974:         // to send the data.  Then we can temporarily remove partitions that are handled by the
975:         // node from the list of available partitions so that the partitioner wouldn't pick
976:         // this partition.
977:         // NOTE: there is no synchronization for metric updates, so drainTimeMs is updated
978:         // first to avoid accidentally marking a partition unavailable if the reader gets
979:         // values between updates.
980:         NodeLatencyStats nodeLatencyStats = nodeStats.computeIfAbsent(nodeId, id -> new NodeLatencyStats(nowMs));
981:         if (canDrain)
982:             nodeLatencyStats.drainTimeMs = nowMs;
983:         nodeLatencyStats.readyTimeMs = nowMs;
984:     }
