542:     private static Compression configureCompression(ProducerConfig config) {
543:         CompressionType type = CompressionType.forName(config.getString(ProducerConfig.COMPRESSION_TYPE_CONFIG));
544:         switch (type) {
545:             case GZIP: {
546:                 return Compression.gzip()
547:                         .level(config.getInt(ProducerConfig.COMPRESSION_GZIP_LEVEL_CONFIG))
548:                         .build();
549:             }
550:             case LZ4: {
551:                 return Compression.lz4()
552:                         .level(config.getInt(ProducerConfig.COMPRESSION_LZ4_LEVEL_CONFIG))
553:                         .build();
554:             }
555:             case ZSTD: {
556:                 return Compression.zstd()
557:                         .level(config.getInt(ProducerConfig.COMPRESSION_ZSTD_LEVEL_CONFIG))
558:                         .build();
559:             }
560:             default:
561:                 return Compression.of(type).build();
562:         }
