569:     private static int configureDeliveryTimeout(ProducerConfig config, Logger log) {
570:         int deliveryTimeoutMs = config.getInt(ProducerConfig.DELIVERY_TIMEOUT_MS_CONFIG);
571:         int lingerMs = lingerMs(config);
572:         int requestTimeoutMs = config.getInt(ProducerConfig.REQUEST_TIMEOUT_MS_CONFIG);
573:         int lingerAndRequestTimeoutMs = (int) Math.min((long) lingerMs + requestTimeoutMs, Integer.MAX_VALUE);
574: 
575:         if (deliveryTimeoutMs < lingerAndRequestTimeoutMs) {
576:             if (config.originals().containsKey(ProducerConfig.DELIVERY_TIMEOUT_MS_CONFIG)) {
577:                 // throw an exception if the user explicitly set an inconsistent value
578:                 throw new ConfigException(ProducerConfig.DELIVERY_TIMEOUT_MS_CONFIG
579:                     + " should be equal to or larger than " + ProducerConfig.LINGER_MS_CONFIG
580:                     + " + " + ProducerConfig.REQUEST_TIMEOUT_MS_CONFIG);
581:             } else {
582:                 // override deliveryTimeoutMs default value to lingerMs + requestTimeoutMs for backward compatibility
583:                 deliveryTimeoutMs = lingerAndRequestTimeoutMs;
584:                 log.warn("{} should be equal to or larger than {} + {}. Setting it to {}.",
585:                     ProducerConfig.DELIVERY_TIMEOUT_MS_CONFIG, ProducerConfig.LINGER_MS_CONFIG,
586:                     ProducerConfig.REQUEST_TIMEOUT_MS_CONFIG, deliveryTimeoutMs);
587:             }
588:         }
589:         return deliveryTimeoutMs;
590:     }
